+impl VirtualTableCursor for CachePagesCursor {
+    fn filter(
+        &mut self,
+        _cx: &Cx,
+        _idx_num: i32,
+        _idx_str: Option<&str>,
+        args: &[SqliteValue],
+    ) -> Result<()> {
+        if !args.is_empty() {
+            return Err(FrankenError::Internal(
+                "fsqlite_cache_pages does not accept arguments".to_owned(),
+            ));
+        }
+        self.rows = self.pager.cache_page_snapshots()?;
+        self.row_idx = 0;
+        Ok(())
+    }
+
+    fn next(&mut self, _cx: &Cx) -> Result<()> {
+        self.row_idx = self.row_idx.saturating_add(1);
+        Ok(())
+    }
+
+    fn eof(&self) -> bool {
+        self.row_idx >= self.rows.len()
+    }
+
+    fn column(&self, ctx: &mut ColumnContext, col: i32) -> Result<()> {
+        let Some(row) = self.rows.get(self.row_idx) else {
+            ctx.set_value(SqliteValue::Null);
+            return Ok(());
+        };
+
+        let value = match col {
+            0 => SqliteValue::Integer(i64::from(row.page_no.get())),
+            1 => row
+                .version_txn_id
+                .and_then(|value| i64::try_from(value).ok())
+                .map_or(SqliteValue::Null, SqliteValue::Integer),
+            2 => match row.queue {
+                Some(PageCacheQueueKind::T1) => SqliteValue::Text("t1".into()),
+                Some(PageCacheQueueKind::T2) => SqliteValue::Text("t2".into()),
+                _ => SqliteValue::Null,
+            },
+            3 => SqliteValue::Integer(i64::from(row.dirty)),
+            4 => SqliteValue::Integer(i64::from(row.ref_count)),
+            5 => SqliteValue::Integer(i64::try_from(row.access_count).unwrap_or(i64::MAX)),
+            _ => SqliteValue::Null,
+        };
+        ctx.set_value(value);
+        Ok(())
+    }
+
+    fn rowid(&self) -> Result<i64> {
+        let Some(row) = self.rows.get(self.row_idx) else {
+            return Ok(0);
+        };
+        Ok(i64::from(row.page_no.get()))
+    }
+}
